  parent_ad     TEXT,
  computed_by   TEXT         NOT NULL,
  ayanamsha     TEXT         NOT NULL,
  created_at    TIMESTAMPTZ  NOT NULL DEFAULT now(),
  UNIQUE (chart_id, system, level, start_date, planet)
);

CREATE INDEX IF NOT EXISTS idx_dasha_periods_chart_system ON dasha_periods(chart_id, system);
CREATE INDEX IF NOT EXISTS idx_dasha_periods_dates ON dasha_periods(start_date, end_date);

